#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        long long A[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
        }
        long long prefixSum[N + 1] = {0};
        for (int i = 0; i < N; i++) {
            prefixSum[i + 1] = prefixSum[i] + A[i];
        }
        int trailingZeros[N + 1] = {0};
        for (int i = 0; i < N; i++) {
            trailingZeros[i + 1] = trailingZeros[i] + (A[i] % 10 == 0);
        }
        int sum = 0;
        while (M--) {
            int type, L, R;
            scanf("%d %d %d", &type, &L, &R);
            if (type == 1) {
                long long X;
                scanf("%lld", &X);
                for (int i = L - 1; i < R; i++) {
                    A[i] *= X;
                }
                prefixSum[N] = 0;
                trailingZeros[N] = 0;
                for (int i = 0; i < N; i++) {
                    prefixSum[i + 1] = prefixSum[i] + A[i];
                    trailingZeros[i + 1] = trailingZeros[i] + (A[i] % 10 == 0);
                }
            } else if (type == 2) {
                long long Y;
                scanf("%lld", &Y);
                for (int i = L - 1; i < R; i++) {
                    A[i] = (i - L + 2) * Y;
                }
                prefixSum[N] = 0;
                trailingZeros[N] = 0;
                for (int i = 0; i < N; i++) {
                    prefixSum[i + 1] = prefixSum[i] + A[i];
                    trailingZeros[i + 1] = trailingZeros[i] + (A[i] % 10 == 0);
                }
            } else {
                long long product = 1;
                for (int i = L - 1; i < R; i++) {
                    product *= A[i];
                }
                int zeros = 0;
                while (product % 10 == 0) {
                    zeros++;
                    product /= 10;
                }
                sum += zeros;
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

